  function beginDash(b,target,warning,reset){b.warning=warning;b.dashAngle=Math.atan2(target.y-b.y,target.x-b.x);b.move=reset;state.hazards.push({kind:'line',x:b.x,y:b.y,angle:b.dashAngle,length:720,width:b.r*1.25,life:warning,max:warning,color:b.color,safe:true})}
